# -*- coding: utf-8 -*-

import ccxt.async_support as ccxt  # noqa: F402

def test_binary_concat():
    exchange = ccxt.Exchange({
        'id': 'sampleexchange',
    })
    # Test 1: Concat two binaries
    binary1 = exchange.string_to_binary('hello')
    binary2 = exchange.string_to_binary(' world')
    result1 = exchange.binary_concat(binary1, binary2)
    assert exchange.binary_to_string(result1) == 'hello world'
    # Test 2: Concat three binaries
    binary3 = exchange.string_to_binary('foo')
    binary4 = exchange.string_to_binary('bar')
    binary5 = exchange.string_to_binary('baz')
    result2 = exchange.binary_concat(binary3, binary4, binary5)
    assert exchange.binary_to_string(result2) == 'foobarbaz'
    # Test 3: Concat with hex bytes
    result3 = exchange.binary_concat(exchange.base16_to_binary('68656c6c6f'), exchange.string_to_binary(' world'))
    assert exchange.binary_to_string(result3) == 'hello world'
